(window.webpackJsonp=window.webpackJsonp||[]).push([[211],{721:function(n,e,a){"use strict";a.r(e);var t=a(3),r=Object(t.a)({},(function(){var n=this,e=n.$createElement,a=n._self._c||e;return a("ContentSlotsDistributor",{attrs:{"slot-key":n.$parent.slotKey}},[a("p",[n._v("【51CTO外电头条】程序员在今天的科技世界中要想成功，仅有编码技能是不够的，在下面的对话中，Google技术领导和经理Ben\nCollins-Sissman(@sussman)与Google工程经理Brian\nFitzpatrick(@therealfitz)一起，讨论了与非程序员同事共事，维护关系的重要性。")]),n._v(" "),a("p",[n._v("Ben和Brian说谦虚、尊重和信任是培养一个愉快的，富有成效的工作环境的重要原则，他们二人将在下周举行的OSCON大会上分享程序员如何很好地与其他同事一起工作。")]),n._v(" "),a("p",[n._v("OSCON会议描述中提到“大规模组织操纵的艺术”，那是什么?")]),n._v(" "),a("p",[n._v("Brian Fitzpatrick:我认为“组织操纵”应有一个度，这意味着我对Google是如何运作的有较好的了解，我可以引导公司朝好的方向发展。")]),n._v(" "),a("p",[n._v("Ben\nCollins-Sussman:我怀疑Fitz说的是否属实，公司并不总是有一种权力结构与组织机构图匹配，它需要一些真正的调查，发现真正的权力关系所在。")]),n._v(" "),a("p",[n._v("Brian Fitzpatrick:据我所知，没有公司能做到权力结构和它们的组织机构图完全匹配，除非他们少于两个人。")]),n._v(" "),a("p",[n._v("程序员如何与非程序员同事沟通?")]),n._v(" "),a("p",[n._v("Ben Collins-Sussman:首先，要看他们的眼睛而不是他们的鞋子，其次，大多数人不会就纯粹的逻辑喋喋不休。")]),n._v(" "),a("p",[n._v("它有助于添加一些情绪的敏感性，例如，讨论时发生一些争执，大多数非工程师不会领情原始的真相，工程师喜欢纯粹的信息，往往期望十足的反馈 -\n代码审查，设计方案等，当你与非技术人员沟通时，仅仅陈述事实并不总是有帮助，你需要以某种方式将事实包装起来，让它们更易于他人吸收。不要在你的反馈中绕圈子，确保对方不需要逐字分析你的反馈，大多数人比程序员更敏感。")]),n._v(" "),a("p",[n._v("Brian\nFitzpatrick:尊重非程序员的能力是关键，你公司里做市场营销，销售或公关的同事，他们不知道编写代码并不意味着他们就是白痴，他们有他们的工作，你有你的工作，除了工程外，还有大量的技能需要学习，我们应该和非工程师同事相互帮助，协同工作，共同提高。")]),n._v(" "),a("p",[n._v("如何与其他程序员协作，有什么建议?")]),n._v(" "),a("p",[n._v("Brian\nFitzpatrick:这是一个广泛的问题，我们的新书将会在这方面提出建议。我们主张采取三个主要的原则:谦虚、尊重和信任(简称HRT)，如果你表现得很谦虚，并尊重你的同事，并信任他们能把事情做好，你和它们建立愉快的，富有成效的工作关系的机会将更大。")]),n._v(" "),a("p",[n._v("当然，你的同事需要获得你的尊重和信任，但我们发现，要信任某人首先就得怀疑他，如果有人不可信任或不值得你尊重，你会很快弄明白。")]),n._v(" "),a("p",[n._v("Ben\nCollins-Sussman:这些原则不仅适用于自己，实际上可以成为一个强大团队的文化基础，我们常说软件工程是一项团队运动，而不是个人运动，围绕HRT培养团队文化是提高生产力，长期保持成功的关键。")]),n._v(" "),a("p",[n._v("项目发生分歧时该如何处理?")]),n._v(" "),a("p",[n._v("Ben\nCollins-Sussman:我认为最好的策略是讨论，并快速达成方向一致的协议，有时双方需要相互做出一些让步，关键是有一套单一的标准和惯例，没有什么比编码风格，组织惯例或设计技术不一致更快让项目变得混乱不堪，因此保持项目一致性很关键。")]),n._v(" "),a("p",[n._v("Brian\nFitzpatrick::这时应该让信任和尊重的团队文化发挥作用，此外，在开始编码之前，为你的团队建立一套编程习惯，坐下来设计你的产品，可以帮你弄清你究竟要做的是什么，以及你想怎么去做。")]),n._v(" "),a("p",[n._v("原文出处:http://answers.oreilly.com/topic/2801-software-engineering-is-a-team-sport-how-programmers-can-deal-with-colleagues-and-non-programmers/\n原文名:Software engineering is a team sport: How programmers can\ndeal with colleagues and non-programmers")])])}),[],!1,null,null,null);e.default=r.exports}}]);